1	type Quote = { premium: number };
2	type Item = { type: string; cursed?: boolean; enchantment?: number };
3	
4	const PROCESSING_FEE = 5;
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  staff: 80,
8	  amulet: 60,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	const ALIKE_BLOCK_SIZE = 3;
14	const ALIKE_BLOCK_PREMIUM = 60;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const LOYALTY_DISCOUNT_RATE = 0.2;
20	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
21	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
22	
23	const basePremiumFor = (item: Item): number =>
24	  BASE_PREMIUM_BY_TYPE[item.type];
25	
26	const curseSurchargeRateFor = (item: Item): number =>
27	  item.cursed ? CURSE_SURCHARGE_RATE : 0;
28	
29	const enchantmentSurchargeRateFor = (item: Item): number =>
30	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
31	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE
32	    : 0;
33	
34	const totalSurchargeRateFor = (item: Item): number =>
35	  curseSurchargeRateFor(item) + enchantmentSurchargeRateFor(item);
36	
37	const itemPremiumFor = (item: Item): number =>
38	  basePremiumFor(item) * (1 + totalSurchargeRateFor(item));
39	
40	const sumItemPremiums = (items: Item[]): number =>
41	  items.reduce((sum, item) => sum + itemPremiumFor(item), 0);
42	
43	const isAlikeBlock = (items: Item[]): boolean =>
44	  items.length === ALIKE_BLOCK_SIZE &&
45	  items.every((item) => item.type === items[0].type);
46	
47	const componentsPremium = (items: Item[]): number =>
48	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
49	
50	const loyaltyDiscountRateFor = (customer?: { yearsWithMHPCO: number }): number =>
51	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD
52	    ? LOYALTY_DISCOUNT_RATE
53	    : 0;
54	
55	const firstInsuranceSurchargeRateFor = (firstInsurance?: boolean): number =>
56	  firstInsurance ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
57	
58	const followUpDiscountRateFor = (followUp?: boolean): number =>
59	  followUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
60	
61	type QuoteInput = {
62	  customer?: { yearsWithMHPCO: number };
63	  firstInsurance?: boolean;
64	  followUp?: boolean;
65	  items: Item[];
66	};
67	
68	const policyAdjustmentRateFor = (input: QuoteInput): number =>
69	  firstInsuranceSurchargeRateFor(input.firstInsurance) -
70	  loyaltyDiscountRateFor(input.customer) -
71	  followUpDiscountRateFor(input.followUp);
72	
73	export const quote = (input: QuoteInput): Quote => {
74	  const componentsTotal = componentsPremium(input.items);
75	  const policyTotal = componentsTotal + componentsTotal * policyAdjustmentRateFor(input);
76	  return { premium: policyTotal + PROCESSING_FEE };
77	};
78	
79	export const claim = (_input: unknown): unknown => undefined;
80

1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote", () => {
6	    it("empty item list returns premium of 5 G (processing fee only)", () => {
7	      expect(quote({ customer: { yearsWithMHPCO: 0 }, items: [] })).toEqual({ premium: 5 });
8	    });
9	    it("single plain sword returns 105 G (100 base + 5 fee)", () => {
10	      expect(quote({
11	        customer: { yearsWithMHPCO: 0 },
12	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
13	      })).toEqual({ premium: 105 });
14	    });
15	    it("single plain amulet returns 65 G (60 base + 5 fee)", () => {
16	      expect(quote({
17	        customer: { yearsWithMHPCO: 0 },
18	        items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
19	      })).toEqual({ premium: 65 });
20	    });
21	    it("single plain staff returns 85 G (80 base + 5 fee)", () => {
22	      expect(quote({
23	        customer: { yearsWithMHPCO: 0 },
24	        items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
25	      })).toEqual({ premium: 85 });
26	    });
27	    it("single plain potion returns 45 G (40 base + 5 fee)", () => {
28	      expect(quote({
29	        customer: { yearsWithMHPCO: 0 },
30	        items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
31	      })).toEqual({ premium: 45 });
32	    });
33	    it("single rune component returns 30 G (25 base + 5 fee)", () => {
34	      expect(quote({
35	        customer: { yearsWithMHPCO: 0 },
36	        items: [{ type: "rune" }],
37	      })).toEqual({ premium: 30 });
38	    });
39	    it("two different items sums their base premiums (sword + amulet → 165 G)", () => {
40	      expect(quote({
41	        customer: { yearsWithMHPCO: 0 },
42	        items: [
43	          { type: "sword", material: "steel", enchantment: 0, cursed: false },
44	          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
45	        ],
46	      })).toEqual({ premium: 165 });
47	    });
48	    it("three alike components form a building block (3 runes → 65 G)", () => {
49	      expect(quote({
50	        customer: { yearsWithMHPCO: 0 },
51	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
52	      })).toEqual({ premium: 65 });
53	    });
54	    it("four alike components do not form a block (4 runes → 105 G)", () => {
55	      expect(quote({
56	        customer: { yearsWithMHPCO: 0 },
57	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
58	      })).toEqual({ premium: 105 });
59	    });
60	    it("two different component types do not form a block (2 runes + 1 moonstone → 80 G)", () => {
61	      expect(quote({
62	        customer: { yearsWithMHPCO: 0 },
63	        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
64	      })).toEqual({ premium: 80 });
65	    });
66	    it("cursed item adds 50% surcharge on that item's base premium", () => {
67	      expect(quote({
68	        customer: { yearsWithMHPCO: 0 },
69	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
70	      })).toEqual({ premium: 155 });
71	    });
72	    it("highly enchanted item (enchantment ≥ 5) adds 30% surcharge", () => {
73	      expect(quote({
74	        customer: { yearsWithMHPCO: 0 },
75	        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
76	      })).toEqual({ premium: 135 });
77	    });
78	    it("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy total", () => {
79	      expect(quote({
80	        customer: { yearsWithMHPCO: 2 },
81	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
82	      })).toEqual({ premium: 85 });
83	    });
84	    it("first insurance adds 10% surcharge per item", () => {
85	      // First insurance is +10% on each item's base premium, applied as policy-level surcharge.
86	      // Sword: 100 base + 10 first insurance = 110 + 5 fee = 115
87	      expect(quote({
88	        customer: { yearsWithMHPCO: 0 },
89	        firstInsurance: true,
90	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
91	      })).toEqual({ premium: 115 });
92	    });
93	    it("follow-up contract gives 15% discount on policy total", () => {
94	      // Follow-up: sword 100 - 15 + 5 = 90
95	      expect(quote({
96	        customer: { yearsWithMHPCO: 0 },
97	        followUp: true,
98	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
99	      })).toEqual({ premium: 90 });
100	    });
101	    it.todo("premium rounded up in MHPCO's favor");
102	    it.todo("unknown item type causes error");
103	  });
104	
105	  describe("claim", () => {
106	    it.todo("standard damage minus 100 G deductible (sword damage 500 → payout 400)");
107	    it.todo("damage to enchantment ≥ 8 item reimbursed at 50% then deductible");
108	    it.todo("damage to dragon-material item fully reimbursed then deductible");
109	    it.todo("payout capped at 2× insurance sum");
110	    it.todo("deductible applies per damage event (multi-item damage)");
111	    it.todo("claim with item not in policy causes error");
112	    it.todo("claim with negative damage amount causes error");
113	  });
114	});
115

